// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract BaseSeasons {
    struct Player {
        address wallet;
        uint256 totalScore;
        uint256 bestScore;
        uint256 gamesPlayed;
        uint256 currentStreak;
        uint256 lastPlayed;
    }

    struct Score {
        address player;
        uint256 gameId;
        uint256 score;
        uint256 timestamp;
        uint256 seasonId;
    }

    uint256 public currentSeason = 1;
    uint256 public seasonStartTime;
    uint256 public constant SEASON_DURATION = 7 days;

    // player address => Player profile
    mapping(address => Player) public players;

    // seasonId => gameId => Score[]
    mapping(uint256 => mapping(uint256 => Score[])) private leaderboards;

    // We can also store the list of players who have participated to calculate top players overall
    address[] public seasonParticipants;
    mapping(uint256 => mapping(address => bool)) public hasParticipatedInSeason;
    mapping(uint256 => mapping(address => uint256)) public playerSeasonTotalScore;

    event ScoreSubmitted(address indexed player, uint256 indexed gameId, uint256 score, uint256 timestamp, uint256 seasonId);
    event StreakUpdated(address indexed player, uint256 newStreak);
    event NewSeasonStarted(uint256 seasonId, uint256 startTime);

    constructor() {
        seasonStartTime = block.timestamp;
    }

    function submitScore(uint256 gameId, uint256 score) external {
        _checkAndStartSeason();

        Player storage p = players[msg.sender];

        // Initialize wallet if new
        if (p.wallet == address(0)) {
            p.wallet = msg.sender;
        }

        // Update streak logic
        if (p.lastPlayed > 0) {
            uint256 timeSinceLast = block.timestamp - p.lastPlayed;
            if (timeSinceLast >= 1 days && timeSinceLast <= 2 days) {
                p.currentStreak++;
                emit StreakUpdated(msg.sender, p.currentStreak);
            } else if (timeSinceLast > 2 days) {
                p.currentStreak = 1; // reset streak
                emit StreakUpdated(msg.sender, p.currentStreak);
            }
        } else {
            p.currentStreak = 1;
        }

        // Update stats
        p.lastPlayed = block.timestamp;
        p.gamesPlayed++;
        p.totalScore += score;
        if (score > p.bestScore) {
            p.bestScore = score;
        }

        // Season total tracking
        if (!hasParticipatedInSeason[currentSeason][msg.sender]) {
            hasParticipatedInSeason[currentSeason][msg.sender] = true;
            seasonParticipants.push(msg.sender);
        }
        playerSeasonTotalScore[currentSeason][msg.sender] += score;

        // Record score in current season leaderboard
        Score memory newScore = Score({
            player: msg.sender,
            gameId: gameId,
            score: score,
            timestamp: block.timestamp,
            seasonId: currentSeason
        });

        leaderboards[currentSeason][gameId].push(newScore);

        emit ScoreSubmitted(msg.sender, gameId, score, block.timestamp, currentSeason);
    }

    function _checkAndStartSeason() internal {
        if (block.timestamp >= seasonStartTime + SEASON_DURATION) {
            currentSeason++;
            seasonStartTime = block.timestamp;

            // Note: In a true production app with many users, we wouldn't loop or keep a growing array
            // but for simplicity we can clear participants or leave it tracking. 
            // We just leave it and iterate correctly in getTopPlayers if needed, 
            // though returning large arrays is bad practice. We will keep it minimal.
            delete seasonParticipants; // reset participants for the new season

            emit NewSeasonStarted(currentSeason, seasonStartTime);
        }
    }

    function startNewSeason() external {
        require(block.timestamp >= seasonStartTime + SEASON_DURATION, "Season not over");
        currentSeason++;
        seasonStartTime = block.timestamp;
        delete seasonParticipants;
        emit NewSeasonStarted(currentSeason, seasonStartTime);
    }

    function getPlayerStats(address player) external view returns (Player memory) {
        return players[player];
    }

    function getLeaderboard(uint256 gameId, uint256 seasonId) external view returns (Score[] memory) {
        return leaderboards[seasonId][gameId];
    }

    // Returns addresses of all participants this season, frontend can sort by score
    // Alternatively, we return the top 10 calculated on chain. Let's do a simple bounded sort on chain for the prompt requirement.
    function getTopPlayers(uint256 seasonId) external view returns (address[] memory topAddresses, uint256[] memory topScores) {
        uint256 count = seasonParticipants.length;
        uint256 returnCount = count > 10 ? 10 : count;

        topAddresses = new address[](returnCount);
        topScores = new uint256[](returnCount);

        // Very basic sorting for view function. Will cost gas for view if called on-chain, but free via RPC.
        // Copy data to memory for sorting
        address[] memory tempAddresses = new address[](count);
        uint256[] memory tempScores = new uint256[](count);

        for (uint256 i = 0; i < count; i++) {
            tempAddresses[i] = seasonParticipants[i];
            tempScores[i] = playerSeasonTotalScore[seasonId][seasonParticipants[i]];
        }

        // Sort descending
        for (uint256 i = 0; i < count; i++) {
            for (uint256 j = i + 1; j < count; j++) {
                if (tempScores[j] > tempScores[i]) {
                    uint256 tScore = tempScores[i];
                    tempScores[i] = tempScores[j];
                    tempScores[j] = tScore;

                    address tAddr = tempAddresses[i];
                    tempAddresses[i] = tempAddresses[j];
                    tempAddresses[j] = tAddr;
                }
            }
        }

        for (uint256 i = 0; i < returnCount; i++) {
            topAddresses[i] = tempAddresses[i];
            topScores[i] = tempScores[i];
        }

        return (topAddresses, topScores);
    }

    function getCurrentSeason() external view returns (uint256) {
        return currentSeason;
    }
}
